export enum Platform {
  Instagram = 'Instagram',
  Facebook = 'Facebook',
  LinkedIn = 'LinkedIn',
  X = 'X',
  TikTok = 'TikTok',
  Pinterest = 'Pinterest',
  All = 'All'
}

export enum ContentGoal {
  Awareness = 'Awareness',
  Engagement = 'Engagement',
  Leads = 'Leads',
  Sales = 'Sales'
}

export enum BrandTone {
  Professional = 'Professional',
  Conversational = 'Conversational',
  Bold = 'Bold',
  Playful = 'Playful'
}

export enum HookStyle {
  Question = 'Question-based',
  Statement = 'Bold statement',
  Contrarian = 'Contrarian',
  Emotional = 'Emotional',
  Educational = 'Educational'
}

export interface StrategyInput {
  platform: Platform;
  goal: ContentGoal;
  tone: BrandTone;
  hookStyle: HookStyle;
  industry?: string;
  exclusions?: string;
  image: File | null;
}

export interface GeneratedContent {
  platformName: string;
  hook: string;
  caption: string;
  overlayText?: string;
  hashtags: string[];
  engagementStrength: 'Low' | 'Medium' | 'High';
  engagementReason: string;
}

export interface LoadingState {
  isLoading: boolean;
  message: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { StrategyInput, GeneratedContent, Platform } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

// Helper to convert File to Base64
const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    results: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          platformName: { type: Type.STRING },
          hook: { type: Type.STRING },
          caption: { type: Type.STRING },
          overlayText: { type: Type.STRING },
          hashtags: { 
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          engagementStrength: { 
            type: Type.STRING,
            enum: ["Low", "Medium", "High"]
          },
          engagementReason: { type: Type.STRING }
        },
        required: ["platformName", "hook", "caption", "hashtags", "engagementStrength", "engagementReason"]
      }
    }
  }
};

export const generateSocialStrategy = async (input: StrategyInput): Promise<GeneratedContent[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing. Please set REACT_APP_GEMINI_API_KEY.");
  }

  if (!input.image) {
    throw new Error("No image provided.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const imagePart = await fileToGenerativePart(input.image);

  let platformInstruction = "";
  if (input.platform === Platform.All) {
    platformInstruction = "Generate content for: Instagram, Facebook, LinkedIn, X, TikTok, and Pinterest.";
  } else {
    platformInstruction = `Generate content strictly for: ${input.platform}.`;
  }

  const userPrompt = `
    Analyze the attached image.

    Platforms: ${platformInstruction}
    Content Goal: ${input.goal}
    Brand Tone: ${input.tone}
    Hook Style: ${input.hookStyle}
    Industry/Context: ${input.industry || "General"}
    Exclusions: ${input.exclusions || "None"}

    Remember: Write in UK English. Be specific to the visual.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [imagePart, { text: userPrompt }]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7, // A bit of creativity for marketing copy
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const parsed = JSON.parse(text);
    return parsed.results || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';
import { Upload, X, Image as ImageIcon } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File | null) => void;
  selectedFile: File | null;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, selectedFile }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const files = e.dataTransfer.files;
    if (files.length > 0 && files[0].type.startsWith('image/')) {
      handleFile(files[0]);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFile(e.target.files[0]);
    }
  };

  const handleFile = (file: File) => {
    onFileSelect(file);
    const url = URL.createObjectURL(file);
    setPreviewUrl(url);
  };

  const clearFile = (e: React.MouseEvent) => {
    e.stopPropagation();
    onFileSelect(null);
    setPreviewUrl(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div 
      onClick={() => fileInputRef.current?.click()}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`
        relative group cursor-pointer border-2 border-dashed rounded-xl p-8 transition-all duration-300
        ${isDragging ? 'border-brand-amber bg-brand-amber/5' : 'border-gray-300 hover:border-brand-amber'}
        ${selectedFile ? 'border-brand-sky bg-brand-sky/5' : 'bg-white'}
      `}
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />

      {selectedFile && previewUrl ? (
        <div className="relative w-full h-64 md:h-80 flex items-center justify-center overflow-hidden rounded-lg">
            <img 
              src={previewUrl} 
              alt="Preview" 
              className="object-contain h-full w-full"
            />
            <button 
              onClick={clearFile}
              className="absolute top-2 right-2 p-2 bg-brand-black/70 text-white rounded-full hover:bg-red-500 transition-colors"
            >
              <X size={16} />
            </button>
            <div className="absolute bottom-2 left-2 px-3 py-1 bg-brand-black/70 text-white text-xs rounded-full">
              {selectedFile.name}
            </div>
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center space-y-4 text-brand-grey py-8">
          <div className={`p-4 rounded-full ${isDragging ? 'bg-brand-amber/20' : 'bg-gray-100 group-hover:bg-brand-amber/10'} transition-colors`}>
            <Upload size={32} className={`${isDragging ? 'text-brand-amber' : 'text-gray-400 group-hover:text-brand-amber'}`} />
          </div>
          <div className="text-center">
            <p className="font-heading font-semibold text-lg text-brand-black">
              Click to upload or drag and drop
            </p>
            <p className="text-sm mt-1">
              Supports high-res Images (PNG, JPG, WEBP)
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

