import React from 'react';
import { GeneratedContent } from '../types';
import { Copy, Hash, Zap, Type, MessageSquare, BarChart } from 'lucide-react';

interface ResultCardProps {
  content: GeneratedContent;
}

const ResultCard: React.FC<ResultCardProps> = ({ content }) => {
  const getEngagementColor = (strength: string) => {
    switch (strength.toLowerCase()) {
      case 'high': return 'text-green-600 bg-green-50 border-green-200';
      case 'medium': return 'text-brand-amberDark bg-yellow-50 border-yellow-200';
      case 'low': return 'text-red-500 bg-red-50 border-red-200';
      default: return 'text-gray-500 bg-gray-50 border-gray-200';
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    // Could add toast here
  };

  const fullCopy = `${content.hook}\n\n${content.caption}\n\n${content.hashtags.join(' ')}`;

  return (
    <div className="bg-white rounded-2xl shadow-md border border-gray-100 overflow-hidden hover:shadow-lg transition-shadow duration-300">
      <div className="bg-brand-black text-white px-6 py-4 flex justify-between items-center">
        <h3 className="font-heading font-bold text-xl">{content.platformName}</h3>
        <button 
          onClick={() => copyToClipboard(fullCopy)}
          className="text-gray-400 hover:text-brand-amber transition-colors text-sm flex items-center gap-1"
          title="Copy full post"
        >
          <Copy size={16} /> Copy
        </button>
      </div>

      <div className="p-6 space-y-6">

        {/* Hook */}
        <div className="space-y-2">
          <div className="flex items-center gap-2 text-brand-sky font-bold text-sm uppercase tracking-wide">
            <Zap size={16} /> <span>The Hook</span>
          </div>
          <div className="p-4 bg-brand-offWhite rounded-lg border-l-4 border-brand-sky font-heading font-semibold text-brand-black text-lg leading-snug">
            "{content.hook}"
          </div>
        </div>

        {/* Caption */}
        <div className="space-y-2">
           <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide">
            <MessageSquare size={16} /> <span>Caption Body</span>
          </div>
          <p className="text-gray-700 whitespace-pre-wrap leading-relaxed font-sans text-[15px]">
            {content.caption}
          </p>
        </div>

        {/* Overlay & Engagement Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

          {/* Overlay Text */}
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide">
              <Type size={16} /> <span>Visual Overlay</span>
            </div>
            <div className="p-3 border border-dashed border-gray-300 rounded-lg text-center text-brand-black font-black uppercase text-xl bg-gray-50">
              {content.overlayText || "N/A"}
            </div>
          </div>

          {/* Engagement */}
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide">
              <BarChart size={16} /> <span>Forecast</span>
            </div>
            <div className={`p-3 border rounded-lg flex flex-col items-center justify-center text-center h-full ${getEngagementColor(content.engagementStrength)}`}>
              <span className="font-bold uppercase tracking-wider text-sm mb-1">{content.engagementStrength} Engagement</span>
              <span className="text-xs opacity-90 leading-tight">{content.engagementReason}</span>
            </div>
          </div>
        </div>

        {/* Hashtags */}
        {content.hashtags && content.hashtags.length > 0 && (
          <div className="pt-4 border-t border-gray-100">
             <div className="flex items-center gap-2 text-gray-400 font-bold text-xs uppercase tracking-wide mb-2">
              <Hash size={14} /> <span>Keywords</span>
            </div>
            <div className="flex flex-wrap gap-2">
              {content.hashtags.map((tag, idx) => (
                <span key={idx} className="text-brand-sky hover:text-brand-skyLight cursor-pointer text-sm font-medium">
                  {tag.startsWith('#') ? tag : `#${tag}`}
                </span>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default ResultCard;

import React, { useState } from 'react';
import { StrategyInput, Platform, ContentGoal, BrandTone, HookStyle, GeneratedContent } from './types';
import FileUpload from './components/FileUpload';
import StrategyForm from './components/StrategyForm';
import ResultCard from './components/ResultCard';
import { generateSocialStrategy } from './services/geminiService';
import { Camera, Layout as LayoutIcon, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [input, setInput] = useState<StrategyInput>({
    platform: Platform.All,
    goal: ContentGoal.Awareness,
    tone: BrandTone.Professional,
    hookStyle: HookStyle.Statement,
    industry: '',
    exclusions: '',
    image: null
  });

  const [results, setResults] = useState<GeneratedContent[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleInputChange = (field: keyof StrategyInput, value: any) => {
    setInput(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerate = async () => {
    if (!input.image) return;

    setLoading(true);
    setError(null);
    setResults([]);

    try {
      const generatedContent = await generateSocialStrategy(input);
      setResults(generatedContent);
    } catch (err) {
      console.error(err);
      setError("Failed to generate content. Please check your API key and try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#F5F5F5]">
      {/* Header */}
      <header className="bg-brand-black text-white sticky top-0 z-50 shadow-md border-b-4 border-brand-amber">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-brand-amber p-2 rounded-lg text-brand-black">
              <Camera size={24} strokeWidth={2.5} />
            </div>
            <div>
              <h1 className="font-heading font-bold text-2xl tracking-tight leading-none">Social Strategist <span className="text-brand-amber">AI</span></h1>
              <p className="text-xs text-gray-400 font-medium tracking-wider uppercase">Visual-First Performance Marketing</p>
            </div>
          </div>
          <div className="hidden md:flex items-center space-x-6 text-sm font-medium text-gray-400">
             <span>v1.0.0</span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <h2 className="font-heading font-bold text-lg mb-4 flex items-center gap-2">
                 <LayoutIcon size={20} className="text-brand-amber" />
                 Source Media
               </h2>
               <FileUpload 
                selectedFile={input.image} 
                onFileSelect={(file) => handleInputChange('image', file)} 
              />
            </div>

            <StrategyForm 
              input={input} 
              onChange={handleInputChange} 
              onSubmit={handleGenerate}
              isLoading={loading}
            />
          </div>

          {/* Right Column: Output */}
          <div className="lg:col-span-8">
            {error && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700 mb-6 animate-fade-in">
                <AlertCircle className="shrink-0 mt-0.5" />
                <div>
                  <h4 className="font-bold">Error</h4>
                  <p className="text-sm">{error}</p>
                </div>
              </div>
            )}

            {!loading && results.length === 0 && !error && (
              <div className="h-full flex flex-col items-center justify-center text-center text-gray-400 min-h-[400px] border-2 border-dashed border-gray-200 rounded-3xl bg-gray-50/50">
                <Camera size={48} className="mb-4 text-gray-300" />
                <h3 className="text-xl font-heading font-semibold text-gray-500">Ready to Strategise</h3>
                <p className="max-w-md mt-2 text-sm">Upload an image and configure your strategy to generate platform-specific content.</p>
              </div>
            )}

            {results.length > 0 && (
              <div className="space-y-8 animate-fade-in">
                <div className="flex items-center justify-between">
                  <h2 className="font-heading font-bold text-2xl text-brand-black">Generated Strategy</h2>
                  <span className="text-sm font-medium bg-brand-sky/10 text-brand-sky px-3 py-1 rounded-full">
                    {results.length} Platform{results.length !== 1 ? 's' : ''} Optimised
                  </span>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {results.map((content, index) => (
                    <ResultCard key={index} content={content} />
                  ))}
                </div>

                <div className="flex justify-center pt-8 pb-12">
                   <button 
                     onClick={handleGenerate}
                     className="bg-transparent border-2 border-brand-black text-brand-black px-8 py-3 rounded-full font-bold hover:bg-brand-black hover:text-white transition-all"
                   >
                     Regenerate All Variations
                   </button>
                </div>
              </div>
            )}

            {loading && (
              <div className="space-y-6">
                 <div className="h-8 bg-gray-200 rounded w-1/3 animate-pulse"></div>
                 <div className="grid gap-6">
                    {[1, 2].map(i => (
                      <div key={i} className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm space-y-4">
                        <div className="h-6 bg-gray-200 rounded w-1/4 animate-pulse"></div>
                        <div className="h-20 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="grid grid-cols-2 gap-4">
                           <div className="h-16 bg-gray-100 rounded animate-pulse"></div>
                           <div className="h-16 bg-gray-100 rounded animate-pulse"></div>
                        </div>
                      </div>
                    ))}
                 </div>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
