interface ResultCardProps {
  content: GeneratedContent;
}

const ResultCard: React.FC<ResultCardProps> = ({ content }) => {
  const [copiedState, setCopiedState] = useState<string | null>(null);

  const getPlatformIcon = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('instagram')) return <Instagram size={20} className="text-brand-amber" />;
    if (n.includes('facebook')) return <Facebook size={20} className="text-brand-amber" />;
    if (n.includes('linkedin')) return <Linkedin size={20} className="text-brand-amber" />;
    if (n.includes('x')) return <Twitter size={20} className="text-brand-amber" />;
    if (n.includes('tiktok')) return <Music size={20} className="text-brand-amber" />;
    if (n.includes('pinterest')) return <Pin size={20} className="text-brand-amber" />;
    return <Share2 size={20} className="text-brand-amber" />;
  };

  const getEngagementColor = (strength: string) => {
    switch (strength.toLowerCase()) {
      case 'high': return 'text-green-600 bg-green-50 border-green-200';
      case 'medium': return 'text-brand-amberDark bg-yellow-50 border-yellow-200';
      case 'low': return 'text-red-500 bg-red-50 border-red-200';
      default: return 'text-gray-500 bg-gray-50 border-gray-200';
    }
  };

  const copyToClipboard = (text: string, sectionKey: string) => {
    navigator.clipboard.writeText(text);
    setCopiedState(sectionKey);
    setTimeout(() => setCopiedState(null), 2000);
  };

  const fullCopy = `${content.hook}\n\n${content.caption}\n\n${content.hashtags.join(' ')}`;

  const CopyButton = ({ text, sectionKey, className, iconSize = 14 }: { text: string, sectionKey: string, className?: string, iconSize?: number }) => {
    const isCopied = copiedState === sectionKey;
    return (
      <button 
        onClick={() => copyToClipboard(text, sectionKey)}
        className={`transition-all duration-200 flex items-center gap-1.5 text-xs font-medium ${className} ${isCopied ? '!text-green-500' : ''}`}
        title="Copy to clipboard"
      >
        {isCopied ? <Check size={iconSize} /> : <Copy size={iconSize} />}
        <span>{isCopied ? 'Copied' : 'Copy'}</span>
      </button>
    );
