        <div className="flex items-center gap-3">
          {getPlatformIcon(content.platformName)}
          <h3 className="font-heading font-bold text-xl">{content.platformName}</h3>
        </div>
        <CopyButton 
          text={fullCopy} 
          sectionKey="full" 
          className="text-gray-400 hover:text-brand-amber" 
          iconSize={16}
        />
      </div>

      <div className="p-6 space-y-6">

        {/* Hook */}
        <div className="space-y-2">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 text-brand-sky font-bold text-sm uppercase tracking-wide">
              <Zap size={16} /> <span>The Hook</span>
            </div>
            <CopyButton 
              text={content.hook} 
              sectionKey="hook" 
              className="text-gray-400 hover:text-brand-sky"
            />
          </div>
          <div className="p-4 bg-brand-offWhite rounded-lg border-l-4 border-brand-sky font-heading font-semibold text-brand-black text-lg leading-snug">
            "{content.hook}"
          </div>
        </div>

        {/* Caption */}
        <div className="space-y-2">
           <div className="flex items-center justify-between">
             <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide">
              <MessageSquare size={16} /> <span>Caption Body</span>
            </div>
            <CopyButton 
              text={content.caption} 
              sectionKey="caption" 
              className="text-gray-400 hover:text-brand-grey"
            />
          </div>
          <p className="text-gray-700 whitespace-pre-wrap leading-relaxed font-sans text-[15px]">
            {content.caption}
          </p>
        </div>

        {/* Overlay & Engagement Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

          {/* Overlay Text */}
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide">
              <Type size={16} /> <span>Visual Overlay</span>
            </div>
            <div className="p-3 border border-dashed border-gray-300 rounded-lg text-center text-brand-black font-black uppercase text-xl bg-gray-50 h-[84px] flex items-center justify-center">
              {content.overlayText || "N/A"}
            </div>
          </div>

          {/* Engagement Indicator with Tooltip Trigger */}
          <div className="space-y-2 relative group">
            <div className="flex items-center gap-2 text-brand-grey font-bold text-sm uppercase tracking-wide cursor-help">
              <BarChart size={16} /> 
              <span>Forecast</span>
              <Info size={14} className="text-gray-400" />
            </div>

            <div className={`p-3 border rounded-lg flex flex-col items-center justify-center text-center h-[84px] transition-all duration-300 cursor-help ${getEngagementColor(content.engagementStrength)}`}>
              <span className="font-bold uppercase tracking-wider text-sm mb-1">{content.engagementStrength} Engagement</span>
              <span className="text-[11px] opacity-90 leading-tight font-medium">{content.engagementReason}</span>
            </div>

            {/* Enhanced Tooltip */}
            <div className="absolute bottom-full left-0 mb-3 w-72 p-4 bg-gray-900 text-white text-xs rounded-xl shadow-2xl opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 pointer-events-none z-30">
              <h4 className="font-bold border-b border-gray-700 pb-2 mb-2 uppercase tracking-tighter text-brand-amber">Benchmark Definitions</h4>
              <div className="space-y-3">
                <div className="flex flex-col gap-1">
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-green-500"></span>
                    <span className="font-bold text-green-400 uppercase tracking-widest text-[9px]">High Engagement</span>
                  </div>
                  <span className="text-gray-400 leading-normal">High shareability/save potential. Resonates emotionally or provides massive utility. Ideal for virality.</span>
                </div>
                <div className="flex flex-col gap-1">
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-brand-amber"></span>
                    <span className="font-bold text-brand-amber uppercase tracking-widest text-[9px]">Medium Engagement</span>
                  </div>
                  <span className="text-gray-400 leading-normal">Strong community retention. Drives steady likes and active comments. Best for brand loyalty.</span>
                </div>
                <div className="flex flex-col gap-1">
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-red-500"></span>
                    <span className="font-bold text-red-400 uppercase tracking-widest text-[9px]">Low Engagement</span>
                  </div>
                  <span className="text-gray-400 leading-normal">Passive reach/impressions. Useful for high-volume awareness or informative updates with low friction.</span>
                </div>
              </div>
              {/* Tooltip Arrow */}
              <div className="absolute top-full left-8 transform -translate-x-1/2 border-[6px] border-transparent border-t-gray-900"></div>
            </div>
          </div>
        </div>

        {/* Hashtags */}
        {content.hashtags && content.hashtags.length > 0 && (
          <div className="pt-4 border-t border-gray-100">
             <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2 text-gray-400 font-bold text-xs uppercase tracking-wide">
                  <Hash size={14} /> <span>Platform Keywords</span>
                </div>
                <CopyButton 
                  text={content.hashtags.join(' ')} 
                  sectionKey="hashtags" 
                  className="text-gray-400 hover:text-brand-sky"
                />
            </div>
            <div className="flex flex-wrap gap-2">
              {content.hashtags.map((tag, idx) => (
                <span key={idx} className="text-brand-sky hover:text-brand-skyLight cursor-pointer text-sm font-medium">
                  {tag.startsWith('#') ? tag : `#${tag}`}
                </span>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
