import React, { useState } from 'react';
import { StrategyInput, Platform, ContentGoal, BrandTone, HookStyle, GeneratedContent } from './types';
import FileUpload from './components/FileUpload';
import StrategyForm from './components/StrategyForm';
import ResultCard from './components/ResultCard';
import { generateSocialStrategy, generateImagePrompt } from './services/geminiService';
import { Camera, Layout as LayoutIcon, AlertCircle, Copy, Check, Wand2, Loader2, X, ClipboardCheck } from 'lucide-react';

const App: React.FC = () => {
  const [input, setInput] = useState<StrategyInput>({
    platform: [Platform.Instagram],
    goal: ContentGoal.Awareness,
    tone: BrandTone.Professional,
    hookStyle: HookStyle.Statement,
    industry: '',
    exclusions: '',
    image: null
  });

  const [results, setResults] = useState<GeneratedContent[]>([]);
  const [imagePrompt, setImagePrompt] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [promptLoading, setPromptLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copiedAll, setCopiedAll] = useState(false);
  const [copiedPrompt, setCopiedPrompt] = useState(false);

  const handleInputChange = (field: keyof StrategyInput, value: any) => {
    setInput(prev => ({ ...prev, [field]: value }));
    if (field === 'image') {
      setImagePrompt(null);
    }
  };

  const handleGenerate = async () => {
    if (!input.image || input.platform.length === 0) return;

    setLoading(true);
    setError(null);
    setResults([]);
    setCopiedAll(false);

    try {
      const generatedContent = await generateSocialStrategy(input);
      setResults(generatedContent);
    } catch (err) {
      console.error(err);
      setError("Failed to generate content. Please check your API key and try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePrompt = async () => {
    if (!input.image) return;
    setPromptLoading(true);
    setError(null);
    try {
      const prompt = await generateImagePrompt(input.image);
      setImagePrompt(prompt);
    } catch (err) {
      console.error(err);
      setError("Failed to generate image prompt.");
    } finally {
      setPromptLoading(false);
    }
  };

  const handleCopyAll = () => {
    if (results.length === 0) return;

    let allContent = `🚀 SOCIAL MEDIA CONTENT BRIEF\n`;
    allContent += `Generated: ${new Date().toLocaleString()}\n`;
    allContent += `Strategy: ${input.goal} | Tone: ${input.tone}\n`;

    if (imagePrompt) {
      allContent += `\n📸 REVERSE ENGINEERED IMAGE PROMPT:\n"${imagePrompt}"\n`;
    }

    allContent += `\n${'='.repeat(30)}\n\n`;

    const platformContent = results.map(res => {
      return `📱 ${res.platformName.toUpperCase()}\n` +
             `Hook: ${res.hook}\n\n` +
             `Caption:\n${res.caption}\n\n` +
             `Visual Overlay: ${res.overlayText || 'N/A'}\n` +
             `Hashtags: ${res.hashtags.join(' ')}\n` +
             `Engagement Forecast: ${res.engagementStrength} (${res.engagementReason})\n` +
             `\n${'-'.repeat(20)}`;
    }).join('\n\n');

    allContent += platformContent;
    allContent += `\n\nGenerated via Social Strategist AI & BuzzCraft (buzzcraft.co.za)`;

    navigator.clipboard.writeText(allContent);
    setCopiedAll(true);
    setTimeout(() => setCopiedAll(false), 2000);
  };

  const handleCopyPrompt = () => {
    if (!imagePrompt) return;
    navigator.clipboard.writeText(imagePrompt);
    setCopiedPrompt(true);
    setTimeout(() => setCopiedPrompt(false), 2000);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#F5F5F5]">
      {/* Header */}
      <header className="bg-brand-black text-white sticky top-0 z-50 shadow-md border-b-4 border-brand-amber">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div>
              <h1 className="font-heading font-bold text-2xl tracking-tight leading-none">Social Strategist <span className="text-brand-amber">AI</span></h1>
              <p className="text-xs text-gray-400 font-medium tracking-wider uppercase">Visual-First Performance Marketing</p>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <h2 className="font-heading font-bold text-lg mb-4 flex items-center justify-between">
                 <div className="flex items-center gap-2">
                   <LayoutIcon size={20} className="text-brand-amber" />
                   Source Media
                 </div>
               </h2>
               <FileUpload 
                selectedFile={input.image} 
                onFileSelect={(file) => handleInputChange('image', file)} 
              />

              {input.image && (
                <div className="mt-4">
                  <button
                    onClick={handleGeneratePrompt}
                    disabled={promptLoading}
                    className={`w-full bg-brand-amber hover:bg-brand-amberDark text-brand-black py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-md active:scale-[0.98] ${!promptLoading && !imagePrompt ? 'animate-soft-pulse' : ''}`}
                  >
                    {promptLoading ? (
                      <Loader2 size={18} className="animate-spin" />
                    ) : (
                      <Wand2 size={18} />
                    )}
                    {promptLoading ? 'Decoding Image...' : 'Create Prompt for this Image'}
                  </button>
                </div>
              )}
            </div>

            {imagePrompt && (
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-brand-amber/30 animate-fade-in relative group">
                <button 
                  onClick={() => setImagePrompt(null)}
                  className="absolute top-3 right-3 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={16} />
                </button>
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-heading font-bold text-sm uppercase tracking-wider text-brand-amberDark">AI Generation Prompt</h3>
