                  <span className="text-gray-400 leading-normal">Passive reach/impressions. Useful for high-volume awareness or informative updates with low friction.</span>
                </div>
              </div>
              <div className="absolute top-full left-8 transform -translate-x-1/2 border-[6px] border-transparent border-t-gray-900"></div>
            </div>
          </div>
        </div>

        {/* Hashtags */}
        {content.hashtags && content.hashtags.length > 0 && (
          <div className="pt-4 border-t border-gray-100">
             <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2 text-gray-400 font-bold text-xs uppercase tracking-wide">
                  <Hash size={14} /> <span>Platform Keywords</span>
                </div>
                <CopyButton 
                  text={content.hashtags.join(' ')} 
                  sectionKey="hashtags" 
                  className="text-gray-400 hover:text-brand-sky"
                />
            </div>
            <div className="flex flex-wrap gap-2">
              {content.hashtags.map((tag, idx) => (
                <span key={idx} className="text-brand-sky hover:text-brand-skyLight cursor-pointer text-sm font-medium">
                  {tag.startsWith('#') ? tag : `#${tag}`}
                </span>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

