import React, { useState } from 'react';
import { StrategyInput, Platform, ContentGoal, BrandTone, HookStyle, GeneratedContent } from './types';
import FileUpload from './components/FileUpload';
import StrategyForm from './components/StrategyForm';
import ResultCard from './components/ResultCard';
import { generateSocialStrategy, generateImagePrompt } from './services/geminiService';
import { Camera, Layout as LayoutIcon, AlertCircle, Copy, Check, Wand2, Loader2, X, ClipboardCheck } from 'lucide-react';

const App: React.FC = () => {
  const [input, setInput] = useState<StrategyInput>({
    platform: [Platform.Instagram],
    goal: ContentGoal.Awareness,
    tone: BrandTone.Professional,
    hookStyle: HookStyle.Statement,
    industry: '',
    exclusions: '',
    image: null
  });

  const [results, setResults] = useState<GeneratedContent[]>([]);
  const [imagePrompt, setImagePrompt] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [promptLoading, setPromptLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copiedAll, setCopiedAll] = useState(false);
  const [copiedPrompt, setCopiedPrompt] = useState(false);

  const handleInputChange = (field: keyof StrategyInput, value: any) => {
    setInput(prev => ({ ...prev, [field]: value }));
    if (field === 'image') {
      setImagePrompt(null);
    }
  };

  const handleGenerate = async () => {
    if (!input.image || input.platform.length === 0) return;

    setLoading(true);
    setError(null);
    setResults([]);
    setCopiedAll(false);

    try {
      const generatedContent = await generateSocialStrategy(input);
      setResults(generatedContent);
    } catch (err) {
      console.error(err);
      setError("Failed to generate content. Please check your API key and try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleGeneratePrompt = async () => {
    if (!input.image) return;
    setPromptLoading(true);
    setError(null);
    try {
      const prompt = await generateImagePrompt(input.image);
      setImagePrompt(prompt);
    } catch (err) {
      console.error(err);
      setError("Failed to generate image prompt.");
    } finally {
      setPromptLoading(false);
    }
  };

  const handleCopyAll = () => {
    if (results.length === 0) return;

    let allContent = `🚀 SOCIAL MEDIA CONTENT BRIEF\n`;
    allContent += `Generated: ${new Date().toLocaleString()}\n`;
    allContent += `Strategy: ${input.goal} | Tone: ${input.tone}\n`;

    if (imagePrompt) {
      allContent += `\n📸 REVERSE ENGINEERED IMAGE PROMPT:\n"${imagePrompt}"\n`;
    }

    allContent += `\n${'='.repeat(30)}\n\n`;

    const platformContent = results.map(res => {
      return `📱 ${res.platformName.toUpperCase()}\n` +
             `Hook: ${res.hook}\n\n` +
             `Caption:\n${res.caption}\n\n` +
             `Visual Overlay: ${res.overlayText || 'N/A'}\n` +
             `Hashtags: ${res.hashtags.join(' ')}\n` +
             `Engagement Forecast: ${res.engagementStrength} (${res.engagementReason})\n` +
             `\n${'-'.repeat(20)}`;
    }).join('\n\n');

    allContent += platformContent;
    allContent += `\n\nGenerated via Social Strategist AI & BuzzCraft (buzzcraft.co.za)`;

    navigator.clipboard.writeText(allContent);
    setCopiedAll(true);
    setTimeout(() => setCopiedAll(false), 2000);
  };

  const handleCopyPrompt = () => {
    if (!imagePrompt) return;
    navigator.clipboard.writeText(imagePrompt);
    setCopiedPrompt(true);
    setTimeout(() => setCopiedPrompt(false), 2000);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-[#F5F5F5]">
      {/* Header */}
      <header className="bg-brand-black text-white sticky top-0 z-50 shadow-md border-b-4 border-brand-amber">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div>
              <h1 className="font-heading font-bold text-2xl tracking-tight leading-none">Social Strategist <span className="text-brand-amber">AI</span></h1>
              <p className="text-xs text-gray-400 font-medium tracking-wider uppercase">Visual-First Performance Marketing</p>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Input & Controls */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
               <h2 className="font-heading font-bold text-lg mb-4 flex items-center justify-between">
                 <div className="flex items-center gap-2">
                   <LayoutIcon size={20} className="text-brand-amber" />
                   Source Media
                 </div>
               </h2>
               <FileUpload 
                selectedFile={input.image} 
                onFileSelect={(file) => handleInputChange('image', file)} 
              />

              {input.image && (
                <div className="mt-4">
                  <button
                    onClick={handleGeneratePrompt}
                    disabled={promptLoading}
                    className={`w-full bg-brand-amber hover:bg-brand-amberDark text-brand-black py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-md active:scale-[0.98] ${!promptLoading && !imagePrompt ? 'animate-soft-pulse' : ''}`}
                  >
                    {promptLoading ? (
                      <Loader2 size={18} className="animate-spin" />
                    ) : (
                      <Wand2 size={18} />
                    )}
                    {promptLoading ? 'Decoding Image...' : 'Create Prompt for this Image'}
                  </button>
                </div>
              )}
            </div>

            {imagePrompt && (
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-brand-amber/30 animate-fade-in relative group">
                <button 
                  onClick={() => setImagePrompt(null)}
                  className="absolute top-3 right-3 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={16} />
                </button>
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-heading font-bold text-sm uppercase tracking-wider text-brand-amberDark">AI Generation Prompt</h3>
                  <button 
                    onClick={handleCopyPrompt}
                    className="text-brand-black hover:text-brand-amber flex items-center gap-1.5 text-xs font-bold"
                  >
                    {copiedPrompt ? <Check size={14} /> : <Copy size={14} />}
                    {copiedPrompt ? 'Copied' : 'Copy Prompt'}
                  </button>
                </div>
                <div className="p-3 bg-gray-50 rounded-lg border border-gray-100 italic text-sm text-gray-700 leading-relaxed">
                  "{imagePrompt}"
                </div>
              </div>
            )}

            <StrategyForm 
              input={input} 
              onChange={handleInputChange} 
              onSubmit={handleGenerate}
              isLoading={loading}
            />
          </div>

          {/* Right Column: Output */}
          <div className="lg:col-span-8">
            {error && (
              <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700 mb-6 animate-fade-in">
                <AlertCircle className="shrink-0 mt-0.5" />
                <div>
                  <h4 className="font-bold">Error</h4>
                  <p className="text-sm">{error}</p>
                </div>
              </div>
            )}

            {!loading && results.length === 0 && !error && (
              <div className="h-full flex flex-col items-center justify-center text-center text-gray-400 min-h-[400px] border-2 border-dashed border-gray-200 rounded-3xl bg-gray-50/50">
                <Camera size={48} className="mb-4 text-gray-300" />
                <h3 className="text-xl font-heading font-semibold text-gray-500">Awaiting Media</h3>
                <p className="max-w-md mt-2 text-sm">Upload an image to start generating platform-native strategies and AI prompts.</p>
              </div>
            )}

            {results.length > 0 && (
              <div className="space-y-6 animate-fade-in">
                {/* Copy All Section */}
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-white p-5 rounded-2xl border border-gray-100 shadow-sm">
                  <div>
                    <h2 className="font-heading font-bold text-2xl text-brand-black">Generated Content</h2>
                    <p className="text-xs text-brand-grey font-medium uppercase tracking-wider mt-1">{results.length} Channels Optimised</p>
                  </div>
                  <button 
                    onClick={handleCopyAll}
                    className={`flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-black border-2 transition-all duration-300 shadow-md hover:shadow-lg active:scale-95 ${
                      copiedAll 
                      ? 'bg-green-500 border-green-500 text-white' 
                      : 'bg-brand-amber border-brand-amber text-brand-black hover:bg-brand-amberDark hover:border-brand-amberDark'
                    }`}
                  >
                    {copiedAll ? <ClipboardCheck size={20} /> : <Copy size={20} />}
                    {copiedAll ? 'BRIEF COPIED!' : 'COPY FULL STRATEGY BRIEF'}
                  </button>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {results.map((content, index) => (
                    <ResultCard key={index} content={content} />
                  ))}
                </div>

                <div className="flex justify-center pt-8 pb-12">
                   <button 
                     onClick={handleGenerate}
                     className="bg-transparent border-2 border-brand-black text-brand-black px-10 py-4 rounded-full font-black hover:bg-brand-black hover:text-white transition-all shadow-sm hover:shadow-md"
                   >
                     REGENERATE ALL VARIATIONS
                   </button>
                </div>
              </div>
            )}

            {loading && (
              <div className="space-y-6">
                 <div className="h-20 bg-white rounded-2xl w-full animate-pulse border border-gray-100 shadow-sm"></div>
                 <div className="grid gap-6">
                    {[1, 2].map(i => (
                      <div key={i} className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm space-y-4">
                        <div className="h-6 bg-gray-200 rounded w-1/4 animate-pulse"></div>
                        <div className="h-20 bg-gray-100 rounded w-full animate-pulse"></div>
                        <div className="grid grid-cols-2 gap-4">
                           <div className="h-16 bg-gray-100 rounded animate-pulse"></div>
                           <div className="h-16 bg-gray-100 rounded animate-pulse"></div>
                        </div>
                      </div>
                    ))}
                 </div>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-brand-black text-white py-12 mt-auto border-t border-gray-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col items-center justify-center text-center gap-8">

          <div className="flex flex-col items-center gap-4">
            <a href='https://buzzcraft.co.za' target='_blank' rel="noopener noreferrer" className="group">
              <img 
                src='https://i.postimg.cc/DwbM1CwR/1000008690.png' 
                border='0' 
                alt='BuzzCraft' 
                className="h-12 md:h-16 opacity-80 group-hover:opacity-100 transition-all duration-300 filter grayscale group-hover:grayscale-0" 
              />
            </a>
            <p className="text-[11px] md:text-xs text-gray-500 font-bold tracking-[0.3em] uppercase">Visual Excellence in Marketing</p>
          </div>

          <div className="space-y-2 border-t border-gray-800 pt-6 w-full max-w-xs">
            <p className="text-[10px] font-bold text-gray-400 tracking-wide uppercase">&copy; {new Date().getFullYear()} Social Strategist AI</p>
            <p className="text-[10px] text-gray-600">
              Developed by <a href="https://buzzcraft.co.za" target="_blank" rel="noopener noreferrer" className="text-brand-amber hover:underline transition-colors">BuzzCraft</a>
            </p>
          </div>

        </div>
      </footer>
    </div>
  );
