import React, { useState } from 'react';
import { GeneratedContent } from '../types';
import { 
  Copy, Hash, Zap, Type, MessageSquare, BarChart, Check, Info,
  Instagram, Facebook, Linkedin, Twitter, Music, Pin, Share2 
} from 'lucide-react';

interface ResultCardProps {
  content: GeneratedContent;
}

const ResultCard: React.FC<ResultCardProps> = ({ content }) => {
  const [copiedState, setCopiedState] = useState<string | null>(null);

  const getPlatformColors = (name: string) => {
    const n = name.toLowerCase();
    if (n.includes('instagram')) return { icon: <Instagram size={28} className="text-[#E4405F]" />, accent: 'bg-[#E4405F]' };
    if (n.includes('facebook')) return { icon: <Facebook size={28} className="text-[#1877F2]" />, accent: 'bg-[#1877F2]' };
    if (n.includes('linkedin')) return { icon: <Linkedin size={28} className="text-[#0077B5]" />, accent: 'bg-[#0077B5]' };
    if (n.includes('x')) return { icon: <Twitter size={28} className="text-white" />, accent: 'bg-white' };
    if (n.includes('tiktok')) return { icon: <Music size={28} className="text-[#00F2EA]" />, accent: 'bg-[#00F2EA]' };
    if (n.includes('pinterest')) return { icon: <Pin size={28} className="text-[#BD081C]" />, accent: 'bg-[#BD081C]' };
    return { icon: <Share2 size={28} className="text-brand-amber" />, accent: 'bg-brand-amber' };
  };

  const platformStyle = getPlatformColors(content.platformName);

  const getEngagementColor = (strength: string) => {
    switch (strength.toLowerCase()) {
      case 'high': return 'text-green-600 bg-green-50 border-green-200';
      case 'medium': return 'text-brand-amberDark bg-yellow-50 border-yellow-200';
      case 'low': return 'text-red-500 bg-red-50 border-red-200';
      default: return 'text-gray-500 bg-gray-50 border-gray-200';
    }
  };

  const copyToClipboard = (text: string, sectionKey: string) => {
    navigator.clipboard.writeText(text);
    setCopiedState(sectionKey);
    setTimeout(() => setCopiedState(null), 2000);
  };

  const fullCopy = `${content.hook}\n\n${content.caption}\n\n${content.hashtags.join(' ')}`;

  const CopyButton = ({ text, sectionKey, className, iconSize = 14 }: { text: string, sectionKey: string, className?: string, iconSize?: number }) => {
    const isCopied = copiedState === sectionKey;
    return (
      <button 
        onClick={() => copyToClipboard(text, sectionKey)}
        className={`transition-all duration-200 flex items-center gap-1.5 text-xs font-bold ${className} ${isCopied ? '!text-green-500' : ''}`}
        title="Copy to clipboard"
      >
        {isCopied ? <Check size={iconSize} /> : <Copy size={iconSize} />}
        <span>{isCopied ? 'Copied' : 'Copy'}</span>
      </button>
    );
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden hover:shadow-2xl transition-all duration-500 group relative">
      {/* Brand Accent Top Strip */}
      <div className={`h-1.5 w-full ${platformStyle.accent}`}></div>

      <div className="bg-brand-black text-white px-8 py-6 flex justify-between items-center relative overflow-hidden">
        {/* Decorative Background Icon */}
        <div className="absolute right-[-10px] top-[-10px] opacity-10 rotate-12 scale-[3]">
          {platformStyle.icon}
        </div>

        <div className="flex items-center gap-4 relative z-10">
