                  >
                    {promptLoading ? (
                      <Loader2 size={18} className="animate-spin" />
                    ) : (
                      <Wand2 size={18} />
                    )}
                    {promptLoading ? 'Decoding Image...' : 'Reverse Engineer Prompt'}
                  </button>
                </div>
              )}
            </div>

            {imagePrompt && (
